import React, { useState } from 'react';
import Header from '../components/Header';
import MoviePlayer from '../components/MoviePlayer';
import { MOVIES } from '../services/api';

const Home = () => {
  const [selectedMovie, setSelectedMovie] = useState(null);

  const containerStyle = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '2rem'
  };

  const titleStyle = {
    fontSize: '1.8rem',
    fontWeight: 600,
    marginBottom: '2rem',
    color: '#eacece',
    borderLeft: '5px solid #8b1e1e',
    paddingLeft: '1rem'
  };

  const gridStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))',
    gap: '2rem'
  };

  const cardStyle = {
    background: '#141111',
    borderRadius: '24px',
    overflow: 'hidden',
    cursor: 'pointer',
    border: '1px solid #2f1c1c',
    transition: 'transform 0.3s, box-shadow 0.3s'
  };

  const cardHoverStyle = {
    transform: 'translateY(-8px)',
    borderColor: '#6a1e1e',
    boxShadow: '0 15px 30px rgba(100, 20, 20, 0.3)'
  };

  const posterStyle = {
    height: '320px',
    background: 'linear-gradient(145deg, #2c1414 0%, #1f0f0f 100%)',
    display: 'flex',
    alignItems: 'flex-end',
    justifyContent: 'center',
    padding: '2rem',
    transition: 'transform 0.3s'
  };

  const posterTextStyle = {
    background: 'rgba(0, 0, 0, 0.7)',
    padding: '0.5rem 1rem',
    borderRadius: '12px',
    color: '#d47b7b',
    fontWeight: '600',
    fontSize: '0.9rem',
    textAlign: 'center',
    backdropFilter: 'blur(5px)',
    border: '1px solid #6a1e1e'
  };

  const titleTextStyle = {
    padding: '1rem',
    textAlign: 'center',
    color: '#eacece',
    fontWeight: '600'
  };

  const yearStyle = {
    color: '#a16565',
    marginLeft: '0.5rem',
    fontWeight: '400',
    fontSize: '0.85rem'
  };

  const [hoveredId, setHoveredId] = useState(null);

  const handleMovieClick = (movie) => {
    setSelectedMovie(movie);
  };

  const handleClosePlayer = () => {
    setSelectedMovie(null);
  };

  return (
    <>
      <Header />
      <main style={containerStyle}>
        <h2 style={titleStyle}>🔴 КАТАЛОГ ФИЛЬМОВ</h2>
        <div style={gridStyle}>
          {Object.values(MOVIES).map(movie => (
            <div 
              key={movie.id} 
              style={{
                ...cardStyle,
                ...(hoveredId === movie.id ? cardHoverStyle : {})
              }}
              onClick={() => handleMovieClick(movie)}
              onMouseEnter={() => setHoveredId(movie.id)}
              onMouseLeave={() => setHoveredId(null)}
            >
              <div style={{
                ...posterStyle,
                ...(hoveredId === movie.id ? { transform: 'scale(1.02)' } : {})
              }}>
                <span style={posterTextStyle}>
                  {movie.title.toUpperCase()}
                </span>
              </div>
              <div style={titleTextStyle}>
                {movie.title}
                <span style={yearStyle}>({movie.year})</span>
              </div>
            </div>
          ))}
        </div>
      </main>
      {selectedMovie && (
        <MoviePlayer movie={selectedMovie} onClose={handleClosePlayer} />
      )}
    </>
  );
};

export default Home;
